using cl_device_id = int;

struct cl_half2 {
  uint16_t x;
  uint16_t y;
};

static inline uint16_t float_to_half_bits(float f) {
  uint32_t x;
  std::memcpy(&x, &f, sizeof(x));
  uint32_t sign = (x >> 31) & 0x1;
  int exp = static_cast<int>((x >> 23) & 0xFF) - 127 + 15;
  uint32_t mant = x & 0x7FFFFF;

  if (exp <= 0) {
    if (exp < -10) return static_cast<uint16_t>(sign << 15);
    mant = (mant | 0x800000) >> (1 - exp);
    return static_cast<uint16_t>((sign << 15) | (mant >> 13));
  } else if (exp >= 31) {
    return static_cast<uint16_t>((sign << 15) | (31 << 10));
  } else {
    return static_cast<uint16_t>((sign << 15) | (exp << 10) | (mant >> 13));
  }
}

static inline float half_bits_to_float(uint16_t h) {
  uint32_t sign = (h >> 15) & 0x1;
  uint32_t exp = (h >> 10) & 0x1F;
  uint32_t mant = h & 0x3FF;

  uint32_t out;
  if (exp == 0) {
    if (mant == 0) {
      out = sign << 31;
    } else {
      exp = 127 - 15 + 1;
      while ((mant & 0x400) == 0) {
        mant <<= 1;
        --exp;
      }
      mant &= 0x3FF;
      out = (sign << 31) | (exp << 23) | (mant << 13);
    }
  } else if (exp == 31) {
    out = (sign << 31) | (0xFF << 23) | (mant << 13);
  } else {
    out = (sign << 31) | ((exp - 15 + 127) << 23) | (mant << 13);
  }

  float f;
  std::memcpy(&f, &out, sizeof(f));
  return f;
}

static inline cl_half2 make_half2(float v) {
  uint16_t h = float_to_half_bits(v);
  return cl_half2{h, h};
}

static inline cl_half2 operator+(const cl_half2& a, const cl_half2& b) {
  return make_half2(half_bits_to_float(a.x) + half_bits_to_float(b.x));
}

static inline cl_half2 operator*(const cl_half2& a, const cl_half2& b) {
  return make_half2(half_bits_to_float(a.x) * half_bits_to_float(b.x));
}

template <typename T>
static inline bool is_equal_val(const T& a, const T& b) {
  return a == b;
}

static inline bool is_equal_val(const cl_half2& a, const cl_half2& b) {
  return a.x == b.x && a.y == b.y;
}

template <typename T>
static inline T zero_val() {
  return static_cast<T>(0);
}
template <>
inline cl_half2 zero_val<cl_half2>() {
  return make_half2(0.0f);
}

template <typename T>
static inline T minus_one_val() {
  return static_cast<T>(-1);
}
template <>
inline cl_half2 minus_one_val<cl_half2>() {
  return make_half2(-1.0f);
}

static inline cl_device_id GetDeviceID(int index, FILE* fout) {
