static inline size_t GetMaxDeviceWGSize(cl_device_id) { return 1u << 20; }

void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

template <int N, typename F>
double benchmark(F&& fn) {
  double acc = 0.0;
  for (int i = 0; i < N; ++i) acc += fn();
  return acc / static_cast<double>(N);
}

template <typename T>
void run_kernel(std::byte* raw_buffer,
                long size,
                bool block_strided,
                size_t workgroupsize,
                unsigned int elements_per_wi,
                unsigned int fusion_degree,
                int compute_iters,
                T seed) {
  T* g_data = reinterpret_cast<T*>(raw_buffer);
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const unsigned int blockSize = static_cast<unsigned int>(workgroupsize);
  const long num_groups =
      (blockSize == 0) ? 0 : (compute_grid_size / static_cast<long>(blockSize));
  const long big_stride =
      num_groups * static_cast<long>(blockSize) * elements_per_wi;

#pragma omp parallel
  {
    std::vector<T> tmps(elements_per_wi);
#pragma omp for schedule(static)
    for (long gid = 0; gid < compute_grid_size; ++gid) {
      long idx;
      long stride;
      if (block_strided) {
        const long group_id =
            (blockSize == 0) ? 0 : (gid / static_cast<long>(blockSize));
        const long local_id =
            (blockSize == 0) ? 0 : (gid % static_cast<long>(blockSize));
        stride = static_cast<long>(blockSize);
        idx = group_id * static_cast<long>(blockSize) * elements_per_wi +
              local_id;
      } else {
        const long grid_size = compute_grid_size;
        stride = grid_size;
        idx = gid;
      }

      for (unsigned int k = 0; k < fusion_degree; k++) {
        for (unsigned int j = 0; j < elements_per_wi; j++) {
          long pos = idx + static_cast<long>(j) * stride +
                     static_cast<long>(k) * big_stride;
          if (pos < 0 || pos >= size) continue;
          T v = g_data[pos];
          for (int i = 0; i < compute_iters; i++) {
            v = v * v + seed;
          }
          tmps[j] = v;
        }

        T sum = zero_val<T>();
        for (unsigned int j = 0; j + 1 < elements_per_wi; j += 2) {
          sum = sum + tmps[j] * tmps[j + 1];
        }

        if (is_equal_val(sum, minus_one_val<T>())) {
          long wpos = idx + static_cast<long>(k) * big_stride;
          if (wpos >= 0 && wpos < size) g_data[wpos] = sum;
        }
      }
    }
  }
}

void runbench_warmup(std::byte* buffer,
                     long size,
                     size_t workgroupsize,
                     bool block_strided) {
  const long reduced_grid_size = size / 256;
  if (reduced_grid_size <= 0) return;
  run_kernel<int16_t>(buffer, reduced_grid_size, block_strided, workgroupsize,
                      1, 1, 0, static_cast<int16_t>(1));
}

void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              std::byte* buffer,
              long size,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool,
              bool block_strided,
              bool enable_dp,
              bool enable_hp) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const int current_compute_iterations = compute_iterations[krn_idx];
  const long long computations =
      (elements_per_wi * (long long)compute_grid_size +
       (2 * elements_per_wi * current_compute_iterations) *
           (long long)compute_grid_size) *
      fusion_degree;
  const long long memoryoperations = size;

  constexpr auto total_bench_iterations = 3;

  double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
    auto ts_start = std::chrono::high_resolution_clock::now();
    run_kernel<float>(buffer, size, block_strided, workgroupsize,
                      elements_per_wi, fusion_degree, current_compute_iterations,
                      1.0f);
    auto ts_end = std::chrono::high_resolution_clock::now();
    return std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
  });

  double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
    if (enable_dp) {
      auto ts_start = std::chrono::high_resolution_clock::now();
      run_kernel<double>(buffer, size, block_strided, workgroupsize,
                         elements_per_wi, fusion_degree,
                         current_compute_iterations, 1.0);
      auto ts_end = std::chrono::high_resolution_clock::now();
      return std::chrono::duration<double, std::milli>(ts_end - ts_start)
          .count();
    } else
      return 0.0;
  });

  double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
    if (enable_hp) {
      auto ts_start = std::chrono::high_resolution_clock::now();
      run_kernel<cl_half2>(buffer, size, block_strided, workgroupsize,
                           elements_per_wi, fusion_degree,
                           current_compute_iterations, cl_half2{15360, 15360});
      auto ts_end = std::chrono::high_resolution_clock::now();
      return std::chrono::duration<double, std::milli>(ts_end - ts_start)
          .count();
    } else
      return 0.0;
  });

  double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
    auto ts_start = std::chrono::high_resolution_clock::now();
    run_kernel<int>(buffer, size, block_strided, workgroupsize, elements_per_wi,
                    fusion_degree, current_compute_iterations, 1);
    auto ts_end = std::chrono::high_resolution_clock::now();
    return std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(cl_half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(cl_half2)) / kernel_time_mad_hp *
          1000. / (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(cl_device_id,
                            double* c,
                            long size,
                            bool block_strided,
                            bool host_allocated,
                            bool use_os_timer,
                            size_t workgroupsize,
                            unsigned int elements_per_wi,
                            unsigned int fusion_degree) {
  const char* benchtype;
  if (block_strided)
    benchtype = "Workgroup";
  else
    benchtype = "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation =
      host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n",
         use_os_timer ? "OS based" : "CL event based");

  bool enable_dp = true;
  bool enable_hp = false;
  if (!enable_dp)
    printf(
        "Warning:                Double precision computations are not "
        "supported\n");
  if (!enable_hp)
    printf(
        "Warning:                Half precision computations are not "
        "supported\n");

  std::vector<std::byte> buffer(size * sizeof(double));
  std::memset(buffer.data(), 0, buffer.size());

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    (void)i;
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  runbench_warmup(buffer.data(), size, workgroupsize, block_strided);

  printf(
      "------------------------------------------------------------------------"
      "----- CSV data "
      "------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++)
    runbench(compute_iterations, i, buffer.data(), size, workgroupsize,
             elements_per_wi, fusion_degree, use_os_timer, block_strided,
             enable_dp, enable_hp);

  printf(
      "------------------------------------------------------------------------"
      "------------------------------------------------------------------------"
      "--------------------\n");

  std::memcpy(c, buffer.data(), size * sizeof(double));
}

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else if ((strcmp(argv[i], "-w") == 0) ||
               (strcmp(argv[i], "--workgroup-stride") == 0)) {
      output->block_strided = true;
    } else if ((strcmp(argv[i], "-H") == 0) ||
               (strcmp(argv[i], "--host-alloc") == 0)) {
      output->host_allocated = true;
    } else if ((strcmp(argv[i], "-t") == 0) ||
               (strcmp(argv[i], "--use-os-timer") == 0)) {
      output->use_os_timer = true;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->device_index = static_cast<int>(value);
          arg_count++;
          break;
        case 1:
          output->wg_size = static_cast<int>(value);
          arg_count++;
          break;
        case 2:
          output->vecwidth = static_cast<unsigned int>(value);
          arg_count++;
          break;
        case 3:
          output->elements_per_wi = static_cast<unsigned int>(value);
          arg_count++;
          break;
        case 4:
          output->fusion_degree = static_cast<unsigned int>(value);
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

int main(int argc, char* argv[]) {
  printf("mixbench-ocl (%s)\n", VERSION_INFO);

  ArgParams args = {1, false, false, false, 256,
                    DEF_VECTOR_SIZE / (1024 * 1024), 8, 4};

  if (!argument_parsing(argc, argv, &args)) {
    printf(
        "Usage: mixbench-ocl [options] [device index [workgroup size [array "
        "size(1024^2) [elements per workitem [fusion degree]]]]]\n");
    printf("\nOptions:\n"
           "  -h or --help              Show this message\n"
           "  -H or --host-alloc        Use host allocated buffer "
           "(CL_MEM_ALLOC_HOST_PTR)\n"
           "  -w or --workgroup-stride  Workitem strides equal to the width of "
           "a workgroup length (default: NDRange length)\n"
           "  -t or --use-os-timer      Use standard OS timer instead of "
           "OpenCL profiling timer\n"
           "\n");

    GetDeviceID(0, stdout);
    exit(1);
  }

  printf("Use \"-h\" argument to see available options\n");

  const size_t VEC_WIDTH = 1024 * 1024 * args.vecwidth;
  unsigned int datasize = static_cast<unsigned int>(VEC_WIDTH * sizeof(double));

  cl_device_id dev_id = GetDeviceID(args.device_index, NULL);

  if (dev_id == 0) {
    fprintf(stderr, "Error: No OpenCL device selected\n");
    exit(1);
  }
  StoreDeviceInfo(dev_id, stdout);

  printf("Buffer size:            %dMB\n", datasize / (1024 * 1024));
  printf("Workgroup size:         %d\n", args.wg_size);
  printf("Elements per workitem:  %d\n", args.elements_per_wi);
  printf("Workitem fusion degree: %d\n", args.fusion_degree);

  if (GetMaxDeviceWGSize(dev_id) < (size_t)args.wg_size) {
    fprintf(stderr, "Error: Unsupported workgroup size (%u).\n", args.wg_size);
    exit(1);
  }

  double* c;
  c = (double*)malloc(datasize);

  mixbenchGPU(dev_id, c, (long)VEC_WIDTH, args.block_strided, args.host_allocated,
              args.use_os_timer, (size_t)args.wg_size, args.elements_per_wi,
              args.fusion_degree);

  free(c);

  return 0;
}
